local Aura = loadstring(game:HttpGet("https://raw.githubusercontent.com/MythicalSouls/Aura/refs/heads/main/Main.lua"))()
local Players = game:GetService("Players")
local Player = Players.LocalPlayer
local Character = Player.Character or Player.CharacterAdded:Wait()
local Humanoid = Character:WaitForChild("Humanoid")
local RunService = game:GetService("RunService")
local ToolFirstEquipped = false
local Streak

if not getgenv().Animator6DLoadedPro then
	loadstring(game:HttpGet("https://raw.githubusercontent.com/gObl00x/Stuff/refs/heads/main/Animator6D.lua"))()
	repeat task.wait() until getgenv().Animator6DLoadedPro
end


local IdleKF = SwordIdle()
local WalkKF = SwordWalk()
local JumpKF = nil

local currentAnim = nil

local function Play(kfseq, looped)
	if currentAnim == kfseq then return end
	if kfseq == nli then return end
	getgenv().Animator6DStop()
	task.wait(0.03)
	getgenv().Animator6D(kfseq, 1, looped ~= false)
	currentAnim = kfseq
end

RunService.RenderStepped:Connect(function()
	if not Character or not Character:FindFirstChild("Humanoid") then return end
	local hum = Humanoid
	local moving = hum.MoveDirection.Magnitude > 0
	local inAir = hum.FloorMaterial == Enum.Material.Air

	if inAir then
		Play(JumpKF, false)
	elseif moving then
		Play(WalkKF, true)
	else
		Play(IdleKF, true)
	end
end)

function Start()
	local Tool = MainTool()
	local Gui = MainGui()
	for i,v in pairs(Gui:GetDescendants()) do
		if v:IsA("TextLabel") then
			v.FontFace = MainFont
		end
	end
	Tool.Parent = Player.Backpack
	Tool.Equipped:Connect(function(mouse)
		if ToolFirstEquipped == false then
			ToolFirstEquipped = true
			Streak = Instance.new("IntValue")
			Streak.Name = "Streak"
			Streak.Parent = Character
			Aura.AddBodyPartsAura(Character, MainAuras():GetChildren())
			Gui.Parent = Player.PlayerGui
			Character:FindFirstChildOfClass("Humanoid").WalkSpeed = 35
			Character:FindFirstChildOfClass("Humanoid").JumpPower = 75
		end
	end)
	Tool.Activated:Connect(function()
		Play(Attack2_Animation(), false)
	end)
	RunService:BindToRenderStep("Stats", 1, function()
		Gui.Kills.KillsText.Text = tostring(Streak.Value)
		Gui.Stats.Frame.Speed.TextLabel.Text = "Walk Speed: " .. tostring(Character:FindFirstChildOfClass("Humanoid").WalkSpeed)
		Gui.Stats.Frame.Jump.TextLabel.Text = "Jump Power: " .. tostring(Character:FindFirstChildOfClass("Humanoid").JumpPower)
		Gui.Stats.Frame.Other.TextLabel.Text = "-[[ Nihility ]]-"
	end)
end

Start()
